1	package com.dojostay.common.security;
2	
3	import jakarta.persistence.AttributeConverter;
4	import jakarta.persistence.Converter;
5	import org.slf4j.Logger;
6	import org.slf4j.LoggerFactory;
7	import org.springframework.beans.factory.annotation.Autowired;
8	import org.springframework.beans.factory.annotation.Value;
9	import org.springframework.stereotype.Component;
10	
11	import javax.crypto.Cipher;
12	import javax.crypto.SecretKey;
13	import javax.crypto.spec.GCMParameterSpec;
14	import javax.crypto.spec.SecretKeySpec;
15	import java.nio.charset.StandardCharsets;
16	import java.security.SecureRandom;
17	import java.util.Base64;
18	
19	/**
20	 * JPA AttributeConverter that encrypts sensitive string columns at rest using
21	 * AES-GCM-256. The encrypted payload is stored as a base64 string with the
22	 * layout {@code "enc:v1:" + base64(iv || ciphertext+tag)} so that:
23	 *
24	 * <ul>
25	 *   <li>Rows written by older versions of this code that still contain
26	 *       plaintext (no {@code enc:v1:} prefix) remain readable until they are
27	 *       rewritten by the normal update flow. This avoids a blocking migration
28	 *       for existing deployments.</li>
29	 *   <li>If the encryption key is not configured we degrade to plaintext rather
30	 *       than crash the entire JPA context — that trade-off is logged loudly on
31	 *       startup and is acceptable for local/offline development, but a warning
32	 *       in {@code application-prod.yml} makes it impossible to miss.</li>
33	 * </ul>
34	 *
35	 * Key lookup: {@code dojostay.security.encryption-key} (32 raw bytes, base64
36	 * encoded). In tests a deterministic key is injected via application-test.yml.
37	 */
38	@Component
39	@Converter(autoApply = false)
40	public class SensitiveStringConverter implements AttributeConverter<String, String> {
41	
42	    private static final Logger log = LoggerFactory.getLogger(SensitiveStringConverter.class);
43	    private static final String PREFIX = "enc:v1:";
44	    private static final int IV_BYTES = 12;
45	    private static final int TAG_BITS = 128;
46	    private static final SecureRandom RANDOM = new SecureRandom();
47	
48	    /**
49	     * Static key holder. The converter is instantiated both by Spring (as a
50	     * bean, so we can receive the injected key) AND by Hibernate reflectively
51	     * when it loads {@code @Convert(converter=...)}. The reflective instance
52	     * does not get a Spring-managed copy, so we stash the key into a static
53	     * field during bean creation and read from it in convertToEntityAttribute
54	     * / convertToDatabaseColumn. This is the standard workaround for making a
55	     * Spring-aware JPA converter.
56	     */
57	    private static volatile SecretKey keyHolder;
58	
59	    public SensitiveStringConverter() {
60	        // Hibernate-built instance, no key injection
61	    }
62	
63	    @Autowired
64	    public SensitiveStringConverter(@Value("${dojostay.security.encryption-key:}") String base64Key) {
65	        if (base64Key == null || base64Key.isBlank()) {
66	            log.warn("dojostay.security.encryption-key is not set — sensitive fields will be stored in PLAINTEXT. "
67	                    + "Set a 32-byte base64 key in application.yml before production deployment.");
68	            keyHolder = null;
69	            return;
70	        }
71	        try {
72	            byte[] raw = Base64.getDecoder().decode(base64Key);
73	            if (raw.length != 32) {
74	                throw new IllegalStateException("encryption key must decode to exactly 32 bytes (256 bits), got "
75	                        + raw.length);
76	            }
77	            keyHolder = new SecretKeySpec(raw, "AES");
78	            log.info("SensitiveStringConverter initialized with AES-GCM-256 key");
79	        } catch (IllegalArgumentException e) {
80	            throw new IllegalStateException("dojostay.security.encryption-key must be base64-encoded", e);
81	        }
82	    }
83	
84	    @Override
85	    public String convertToDatabaseColumn(String attribute) {
86	        if (attribute == null) return null;
87	        SecretKey key = keyHolder;
88	        if (key == null) {
89	            // No key: degrade to plaintext — see class comment.
90	            return attribute;
91	        }
92	        try {
93	            byte[] iv = new byte[IV_BYTES];
94	            RANDOM.nextBytes(iv);
95	            Cipher c = Cipher.getInstance("AES/GCM/NoPadding");
96	            c.init(Cipher.ENCRYPT_MODE, key, new GCMParameterSpec(TAG_BITS, iv));
97	            byte[] ciphertext = c.doFinal(attribute.getBytes(StandardCharsets.UTF_8));
98	            byte[] combined = new byte[iv.length + ciphertext.length];
99	            System.arraycopy(iv, 0, combined, 0, iv.length);
100	            System.arraycopy(ciphertext, 0, combined, iv.length, ciphertext.length);
101	            return PREFIX + Base64.getEncoder().encodeToString(combined);
102	        } catch (Exception e) {
103	            throw new IllegalStateException("sensitive field encryption failed", e);
104	        }
105	    }
106	
107	    @Override
108	    public String convertToEntityAttribute(String dbData) {
109	        if (dbData == null) return null;
110	        if (!dbData.startsWith(PREFIX)) {
111	            // Legacy plaintext row — pass through untouched.
112	            return dbData;
113	        }
114	        SecretKey key = keyHolder;
115	        if (key == null) {
116	            // Stored encrypted but no key available: surface the marker so the
117	            // caller knows the value cannot be decrypted in this process.
118	            return "[encrypted]";
119	        }
120	        try {
121	            byte[] combined = Base64.getDecoder().decode(dbData.substring(PREFIX.length()));
122	            byte[] iv = new byte[IV_BYTES];
123	            System.arraycopy(combined, 0, iv, 0, IV_BYTES);
124	            byte[] ciphertext = new byte[combined.length - IV_BYTES];
125	            System.arraycopy(combined, IV_BYTES, ciphertext, 0, ciphertext.length);
126	            Cipher c = Cipher.getInstance("AES/GCM/NoPadding");
127	            c.init(Cipher.DECRYPT_MODE, key, new GCMParameterSpec(TAG_BITS, iv));
128	            return new String(c.doFinal(ciphertext), StandardCharsets.UTF_8);
129	        } catch (Exception e) {
130	            throw new IllegalStateException("sensitive field decryption failed", e);
131	        }
132	    }
133	}
