1	<script setup lang="ts">
2	import { onMounted, ref } from 'vue';
3	import { studentsApi, type Student } from '@/api/students';
4	import { ApiException } from '@/api/client';
5	import { useToast } from '@/composables/useToast';
6	
7	const toast = useToast();
8	const loading = ref(false);
9	const students = ref<Student[]>([]);
10	
11	async function load() {
12	  loading.value = true;
13	  try {
14	    students.value = await studentsApi.list();
15	  } catch (err) {
16	    toast.error(err instanceof ApiException ? err.apiError.message : 'Failed to load students');
17	  } finally {
18	    loading.value = false;
19	  }
20	}
21	
22	async function downloadTemplate() {
23	  try {
24	    const blob = await studentsApi.importTemplate();
25	    const url = URL.createObjectURL(blob);
26	    const a = document.createElement('a');
27	    a.href = url;
28	    a.download = 'student-import-template.csv';
29	    a.click();
30	    URL.revokeObjectURL(url);
31	  } catch (err) {
32	    toast.error('Failed to download template');
33	  }
34	}
35	
36	onMounted(load);
37	</script>
38	
