2	import { computed } from 'vue';
3	import { useAuthStore } from '@/stores/auth';
4	
5	const auth = useAuthStore();
6	
7	const greeting = computed(() => {
8	  const hour = new Date().getHours();
9	  if (hour < 12) return 'Good morning';
10	  if (hour < 18) return 'Good afternoon';
11	  return 'Good evening';
12	});
13	
14	// Phase 1 placeholder dashboards. Each upcoming phase will replace the corresponding
15	// section with a real role-tailored view (Student, Photographer, Staff, Admin).
16	const sections = computed(() => {
17	  switch (auth.primaryRole) {
18	    case 'STUDENT':
19	      return [
20	        'Your enrollment status',
21	        'Upcoming training bookings',
22	        'Housing assignment',
23	        'Recent notifications',
24	      ];
25	    case 'PHOTOGRAPHER':
26	      return ['Assignments', 'Upcoming events', 'Notifications'];
27	    case 'STAFF':
28	      return [
29	        'Moderation queue',
30	        'Credential review queue',
31	        "Today's bookings",
32	        'Anomaly alerts',
33	      ];
34	    case 'ADMIN':
35	      return [
36	        'User & role management',
37	        'Feature toggles',
38	        'Backup status',
39	        'Locked accounts',
40	      ];
41	    default:
42	      return [];
43	  }
44	});
45	</script>
