50	      <h1>{{ greeting }}, {{ auth.user?.fullName }}</h1>
51	      <p class="muted">
52	        Signed in as
53	        <strong>{{ auth.user?.username }}</strong>
54	        ({{ auth.user?.primaryRole }})
55	      </p>
56	    </header>
57	
58	    <div class="grid">
59	      <div v-for="title in sections" :key="title" class="card">
60	        <h3>{{ title }}</h3>
61	        <p class="placeholder">
62	          This view will be implemented in a later phase. Phase 1 ships the foundation,
63	          authentication, lockout, audit logging, and the role-aware shell only.
64	        </p>
