1	package com.dojostay.scopes;
2	
3	import com.dojostay.audit.AuditAction;
4	import com.dojostay.audit.AuditService;
5	import com.dojostay.auth.CurrentUser;
6	import com.dojostay.auth.CurrentUserResolver;
7	import com.dojostay.organizations.FacilityScopeType;
8	import com.dojostay.roles.UserRoleType;
9	import org.springframework.stereotype.Service;
10	import org.springframework.transaction.annotation.Transactional;
11	
12	import java.util.HashSet;
13	import java.util.List;
14	import java.util.Set;
15	import java.util.stream.Collectors;
16	
17	/**
18	 * Resolves the effective data scope for a user and manages the data_scope_rules table.
19	 *
20	 * <p>Central rule: any user holding the {@code ADMIN} role gets an
21	 * {@link EffectiveScope#fullAccess()} response — this is the intentional
22	 * cross-organization admin bypass. All other users are restricted to the union of
23	 * their scope rules.
24	 */
25	@Service
26	public class DataScopeService {
27	
28	    private final DataScopeRuleRepository ruleRepository;
29	    private final AuditService auditService;
30	
31	    public DataScopeService(DataScopeRuleRepository ruleRepository, AuditService auditService) {
32	        this.ruleRepository = ruleRepository;
33	        this.auditService = auditService;
34	    }
35	
36	    /**
37	     * Computes the effective scope for the currently-authenticated user.
38	     *
39	     * <p>If no one is authenticated (e.g. in a background job), this returns
40	     * {@link EffectiveScope#empty()} — no access.
41	     */
42	    @Transactional(readOnly = true)
43	    public EffectiveScope forCurrentUser() {
44	        return CurrentUserResolver.current()
45	                .map(this::forUser)
46	                .orElseGet(EffectiveScope::empty);
47	    }
48	
49	    /**
50	     * Computes the effective scope for an arbitrary user (e.g. as part of admin UI
51	     * previews).
52	     */
53	    @Transactional(readOnly = true)
54	    public EffectiveScope forUser(CurrentUser user) {
55	        if (hasFullAccess(user)) {
56	            return EffectiveScope.fullAccess();
57	        }
58	        return readRules(user.id());
59	    }
60	
61	    @Transactional(readOnly = true)
62	    public EffectiveScope forUserId(Long userId, boolean isAdmin) {
63	        if (isAdmin) {
64	            return EffectiveScope.fullAccess();
65	        }
66	        return readRules(userId);
67	    }
68	
69	    /**
70	     * Replaces the full set of scope rules for the target user. Emits a single audit
71	     * record describing the change.
72	     */
73	    @Transactional
74	    public void replaceRules(Long targetUserId, List<DataScopeRule> newRules, String actorSourceIp) {
75	        ruleRepository.deleteByUserId(targetUserId);
76	        for (DataScopeRule rule : newRules) {
77	            rule.setUserId(targetUserId);
78	            ruleRepository.save(rule);
79	        }
80	        CurrentUser actor = CurrentUserResolver.current().orElse(null);
81	        auditService.record(
82	                AuditAction.DATA_SCOPE_CHANGED,
83	                actor != null ? actor.id() : null,
84	                actor != null ? actor.username() : "system",
85	                "USER",
86	                String.valueOf(targetUserId),
87	                "Data scope rules replaced; new count=" + newRules.size(),
88	                actorSourceIp
89	        );
90	    }
91	
92	    public boolean hasFullAccess(CurrentUser user) {
93	        if (user == null) return false;
94	        if (user.primaryRole() == UserRoleType.ADMIN) return true;
95	        return user.roles() != null && user.roles().contains("ADMIN");
96	    }
97	
98	    private EffectiveScope readRules(Long userId) {
99	        List<DataScopeRule> rules = ruleRepository.findByUserId(userId);
100	        Set<Long> orgs = collect(rules, FacilityScopeType.ORGANIZATION);
101	        Set<Long> depts = collect(rules, FacilityScopeType.DEPARTMENT);
102	        Set<Long> areas = collect(rules, FacilityScopeType.FACILITY_AREA);
103	        return new EffectiveScope(false, orgs, depts, areas);
104	    }
105	
106	    private static Set<Long> collect(List<DataScopeRule> rules, FacilityScopeType type) {
107	        return rules.stream()
108	                .filter(r -> r.getScopeType() == type)
109	                .map(DataScopeRule::getScopeTargetId)
110	                .collect(Collectors.toCollection(HashSet::new));
111	    }
112	}
