1	package com.dojostay.scopes;
2	
3	import jakarta.persistence.criteria.Path;
4	import org.springframework.data.jpa.domain.Specification;
5	
6	import java.util.Set;
7	
8	/**
9	 * Generic JPA Specification helpers that translate an {@link EffectiveScope} into a
10	 * query predicate for any entity {@code T} that carries {@code organizationId},
11	 * {@code departmentId}, or {@code facilityAreaId} fields.
12	 *
13	 * <p>Use like:
14	 * <pre>{@code
15	 *   Specification<User> scopeSpec = DataScopeSpec.byOrganization("organizationId", scope);
16	 *   Page<User> page = userRepository.findAll(scopeSpec.and(otherFilters), pageable);
17	 * }</pre>
18	 *
19	 * <p>Semantics:
20	 * <ul>
21	 *   <li>If the scope has {@code fullAccess == true}, returns a "no restriction" spec
22	 *       (null predicate).</li>
23	 *   <li>If the scope set is non-empty, filters to {@code field IN (ids)}.</li>
24	 *   <li>If the scope set is empty, returns a "never match" spec so unscoped non-admin
25	 *       users can never see anything. This is a deliberate deny-by-default posture.</li>
26	 * </ul>
27	 */
28	public final class DataScopeSpec {
29	
30	    private DataScopeSpec() {
31	    }
32	
33	    public static <T> Specification<T> byOrganization(String field, EffectiveScope scope) {
34	        return byField(field, scope.fullAccess(), scope.organizationIds());
35	    }
36	
37	    public static <T> Specification<T> byDepartment(String field, EffectiveScope scope) {
38	        return byField(field, scope.fullAccess(), scope.departmentIds());
39	    }
40	
41	    public static <T> Specification<T> byFacilityArea(String field, EffectiveScope scope) {
42	        return byField(field, scope.fullAccess(), scope.facilityAreaIds());
43	    }
44	
45	    private static <T> Specification<T> byField(String field, boolean fullAccess, Set<Long> ids) {
46	        return (root, query, cb) -> {
47	            if (fullAccess) {
48	                return cb.conjunction(); // always true
49	            }
50	            if (ids == null || ids.isEmpty()) {
51	                return cb.disjunction(); // always false — deny by default
52	            }
53	            Path<Long> path = root.get(field);
54	            return path.in(ids);
55	        };
56	    }
57	}
