9	import com.dojostay.common.exception.NotFoundException;
10	import com.dojostay.roles.Role;
11	import com.dojostay.roles.RoleRepository;
12	import com.dojostay.scopes.DataScopeService;
13	import com.dojostay.scopes.DataScopeSpec;
14	import com.dojostay.scopes.EffectiveScope;
15	import com.dojostay.users.dto.AssignRolesRequest;
16	import com.dojostay.users.dto.CreateUserRequest;
17	import com.dojostay.users.dto.UpdateUserRequest;
18	import com.dojostay.users.dto.UserResponse;
19	import org.springframework.data.domain.Page;
20	import org.springframework.data.domain.Pageable;
21	import org.springframework.data.jpa.domain.Specification;
22	import org.springframework.http.HttpStatus;
23	import org.springframework.security.crypto.password.PasswordEncoder;
24	import org.springframework.stereotype.Service;
25	import org.springframework.transaction.annotation.Transactional;
26	
27	import java.util.HashSet;
28	import java.util.Set;
29	import java.util.stream.Collectors;
30	
31	/**
32	 * Admin-facing user management service.
33	 *
34	 * <p>All list queries go through {@link DataScopeSpec#byOrganization} so non-admin
35	 * staff can only see users belonging to organizations they have been granted a scope
36	 * rule for. This is the Phase 2 proof point: the scoped query filter is enforced at
37	 * the repository layer, not the controller layer, so it cannot be bypassed by a
38	 * forgotten check.
39	 */
40	@Service
41	public class UserService {
42	
43	    private final UserRepository userRepository;
44	    private final RoleRepository roleRepository;
45	    private final PasswordEncoder passwordEncoder;
46	    private final PasswordPolicyValidator passwordPolicyValidator;
47	    private final DataScopeService dataScopeService;
48	    private final AuditService auditService;
49	
50	    public UserService(UserRepository userRepository,
51	                       RoleRepository roleRepository,
52	                       PasswordEncoder passwordEncoder,
53	                       PasswordPolicyValidator passwordPolicyValidator,
54	                       DataScopeService dataScopeService,
55	                       AuditService auditService) {
56	        this.userRepository = userRepository;
57	        this.roleRepository = roleRepository;
58	        this.passwordEncoder = passwordEncoder;
59	        this.passwordPolicyValidator = passwordPolicyValidator;
60	        this.dataScopeService = dataScopeService;
61	        this.auditService = auditService;
62	    }
63	
64	    @Transactional(readOnly = true)
65	    public Page<UserResponse> list(Pageable pageable) {
66	        EffectiveScope scope = dataScopeService.forCurrentUser();
67	        Specification<User> scopeSpec = DataScopeSpec.byOrganization("organizationId", scope);
68	        return userRepository.findAll(scopeSpec, pageable).map(UserService::toResponse);
69	    }
70	
71	    @Transactional(readOnly = true)
72	    public UserResponse get(Long id) {
73	        User user = loadAccessible(id);
74	        return toResponse(user);
75	    }
76	
77	    @Transactional
78	    public UserResponse create(CreateUserRequest req, String sourceIp) {
79	        if (userRepository.existsByUsername(req.username())) {
80	            throw new BusinessException("USERNAME_TAKEN",
81	                    "A user with that username already exists",
82	                    HttpStatus.CONFLICT);
83	        }
84	        var policy = passwordPolicyValidator.validate(req.password());
85	        if (!policy.valid()) {
86	            throw new BusinessException("WEAK_PASSWORD",
87	                    String.join("; ", policy.failures()),
88	                    HttpStatus.BAD_REQUEST);
89	        }
90	
91	        User user = new User();
92	        user.setUsername(req.username());
93	        user.setFullName(req.fullName());
94	        user.setEmail(req.email());
95	        user.setPrimaryRole(req.primaryRole());
96	        user.setOrganizationId(req.organizationId());
97	        user.setPasswordHash(passwordEncoder.encode(req.password()));
98	        user.setEnabled(true);
99	        user.setRoles(resolveRoles(req.roleCodes()));
100	        User saved = userRepository.save(user);
101	
102	        auditRoleChange(saved, req.roleCodes(), "Created user", AuditAction.USER_CREATED, sourceIp);
103	        return toResponse(saved);
104	    }
105	
106	    @Transactional
107	    public UserResponse update(Long id, UpdateUserRequest req, String sourceIp) {
108	        User user = loadAccessible(id);
109	        if (req.fullName() != null) user.setFullName(req.fullName());
110	        if (req.email() != null) user.setEmail(req.email());
111	        if (req.organizationId() != null) user.setOrganizationId(req.organizationId());
112	        if (req.enabled() != null && req.enabled() != user.isEnabled()) {
113	            user.setEnabled(req.enabled());
114	            auditService.record(
115	                    req.enabled() ? AuditAction.USER_ENABLED : AuditAction.USER_DISABLED,
116	                    actorId(), actorUsername(),
117	                    "USER", String.valueOf(user.getId()),
118	                    req.enabled() ? "User enabled" : "User disabled",
119	                    sourceIp
120	            );
121	        }
122	        User saved = userRepository.save(user);
123	        auditService.record(AuditAction.USER_UPDATED, actorId(), actorUsername(),
124	                "USER", String.valueOf(saved.getId()), "User profile updated", sourceIp);
125	        return toResponse(saved);
126	    }
127	
128	    @Transactional
129	    public UserResponse assignRoles(Long id, AssignRolesRequest req, String sourceIp) {
130	        User user = loadAccessible(id);
131	        Set<String> before = user.getRoles().stream().map(Role::getCode).collect(Collectors.toSet());
132	        user.setRoles(resolveRoles(req.roleCodes()));
133	        User saved = userRepository.save(user);
134	
135	        Set<String> added = new HashSet<>(req.roleCodes());
136	        added.removeAll(before);
137	        Set<String> removed = new HashSet<>(before);
138	        removed.removeAll(req.roleCodes());
139	
140	        for (String code : added) {
141	            auditService.record(AuditAction.ROLE_ASSIGNED, actorId(), actorUsername(),
142	                    "USER", String.valueOf(saved.getId()),
143	                    "Role assigned: " + code, sourceIp);
144	        }
145	        for (String code : removed) {
146	            auditService.record(AuditAction.ROLE_REVOKED, actorId(), actorUsername(),
147	                    "USER", String.valueOf(saved.getId()),
148	                    "Role revoked: " + code, sourceIp);
149	        }
150	        return toResponse(saved);
151	    }
152	
153	    /**
154	     * Loads a user by id, but first verifies the current user's data scope allows
155	     * visibility. Non-admins cannot read or write users outside their scope.
156	     */
157	    private User loadAccessible(Long id) {
158	        User user = userRepository.findById(id)
159	                .orElseThrow(() -> new NotFoundException("User not found"));
160	        EffectiveScope scope = dataScopeService.forCurrentUser();
161	        if (scope.fullAccess()) {
162	            return user;
163	        }
164	        if (user.getOrganizationId() == null || !scope.hasOrganization(user.getOrganizationId())) {
165	            // Surface as 404 rather than 403 to avoid leaking existence of out-of-scope users.
166	            throw new NotFoundException("User not found");
167	        }
168	        return user;
169	    }
170	
171	    private Set<Role> resolveRoles(Set<String> codes) {
172	        if (codes == null || codes.isEmpty()) return new HashSet<>();
173	        Set<Role> out = new HashSet<>();
174	        for (String code : codes) {
175	            Role r = roleRepository.findByCode(code)
176	                    .orElseThrow(() -> new BusinessException("UNKNOWN_ROLE",
177	                            "Unknown role code: " + code, HttpStatus.BAD_REQUEST));
178	            out.add(r);
179	        }
180	        return out;
181	    }
182	
183	    private void auditRoleChange(User user, Set<String> addedCodes,
184	                                 String summary, AuditAction action, String sourceIp) {
185	        auditService.record(action, actorId(), actorUsername(), "USER",
186	                String.valueOf(user.getId()), summary, sourceIp);
187	        if (addedCodes != null) {
188	            for (String code : addedCodes) {
189	                auditService.record(AuditAction.ROLE_ASSIGNED, actorId(), actorUsername(),
190	                        "USER", String.valueOf(user.getId()),
191	                        "Role assigned: " + code, sourceIp);
192	            }
193	        }
194	    }
195	
196	    private static Long actorId() {
197	        return CurrentUserResolver.current().map(CurrentUser::id).orElse(null);
198	    }
199	
200	    private static String actorUsername() {
201	        return CurrentUserResolver.current().map(CurrentUser::username).orElse("system");
202	    }
203	
204	    private static UserResponse toResponse(User u) {
205	        return new UserResponse(
206	                u.getId(),
207	                u.getUsername(),
208	                u.getFullName(),
209	                u.getEmail(),
210	                u.getPrimaryRole(),
211	                u.isEnabled(),
212	                u.getOrganizationId(),
213	                u.getRoles().stream().map(Role::getCode).collect(Collectors.toSet()),
214	                u.getCreatedAt(),
215	                u.getUpdatedAt()
216	        );
217	    }
218	}
