169	    /**
170	     * Minimal CSV importer. Expected headers:
171	     * {@code externalId,fullName,email,phone,skillLevel,school,program,classGroup,housingAssignment}.
172	     * Rows missing the required {@code fullName} column are rejected. Rows
173	     * whose externalId already exists in the same organization are skipped
174	     * (idempotent re-run). All rejected rows are collected into a CSV error
175	     * report written to {@code <java.io.tmpdir>/dojostay-import-errors/} so
176	     * the operator can download the complete list — the API response only
177	     * surfaces the first {@value #MAX_SAMPLE_ERRORS} rows to keep the envelope
178	     * bounded on massive imports.
179	     */
180	    @Transactional
181	    public BulkImportResult importCsv(Long organizationId, InputStream csvInput, String sourceIp) {
182	        assertOrgAccessible(organizationId);
183	
184	        BulkImportJob job = new BulkImportJob();
185	        job.setKind("STUDENTS");
186	        job.setOrganizationId(organizationId);
187	        job.setSubmittedByUserId(actorId());
188	        job.setStatus(BulkImportJob.Status.RUNNING);
189	        job = jobRepository.save(job);
190	
191	        int total = 0;
192	        int created = 0;
193	        int skipped = 0;
194	        int failed = 0;
195	        List<BulkImportResult.RowError> sample = new ArrayList<>();
196	        List<BulkImportResult.RowError> allErrors = new ArrayList<>();
197	
198	        try (BufferedReader reader = new BufferedReader(
199	                new InputStreamReader(csvInput, StandardCharsets.UTF_8))) {
200	            String headerLine = reader.readLine();
201	            if (headerLine == null || headerLine.isBlank()) {
202	                throw new BusinessException("EMPTY_CSV", "CSV input is empty", HttpStatus.BAD_REQUEST);
203	            }
204	            Map<String, Integer> cols = indexHeader(headerLine);
205	            requireColumn(cols, "fullName");
206	
207	            String line;
208	            int lineNumber = 1;
209	            while ((line = reader.readLine()) != null) {
210	                lineNumber++;
211	                if (line.isBlank()) continue;
212	                total++;
213	                try {
214	                    String[] fields = splitCsv(line);
215	                    String fullName = cell(fields, cols, "fullName");
216	                    if (fullName == null || fullName.isBlank()) {
217	                        failed++;
218	                        recordError(sample, allErrors, lineNumber,
219	                                "MISSING_NAME", "fullName is required");
220	                        continue;
221	                    }
222	                    String externalId = cell(fields, cols, "externalId");
223	                    if (externalId != null && !externalId.isBlank()
224	                            && studentRepository
225	                                    .findByOrganizationIdAndExternalId(organizationId, externalId)
226	                                    .isPresent()) {
227	                        skipped++;
228	                        continue;
229	                    }
230	
231	                    Student s = new Student();
232	                    s.setOrganizationId(organizationId);
233	                    s.setExternalId(externalId);
234	                    s.setFullName(fullName);
235	                    s.setEmail(cell(fields, cols, "email"));
236	                    s.setPhone(cell(fields, cols, "phone"));
237	                    s.setSkillLevel(cell(fields, cols, "skillLevel"));
238	                    s.setSchool(cell(fields, cols, "school"));
239	                    s.setProgram(cell(fields, cols, "program"));
240	                    s.setClassGroup(cell(fields, cols, "classGroup"));
241	                    s.setHousingAssignment(cell(fields, cols, "housingAssignment"));
242	                    s.setEnrollmentStatus(EnrollmentStatus.PROSPECT);
243	                    studentRepository.save(s);
244	                    created++;
245	                } catch (RuntimeException ex) {
246	                    failed++;
247	                    recordError(sample, allErrors, lineNumber, "ROW_FAILED", ex.getMessage());
248	                }
249	            }
250	        } catch (IOException ioe) {
251	            throw new BusinessException("CSV_READ_FAILED",
252	                    "Could not read CSV: " + ioe.getMessage(), HttpStatus.BAD_REQUEST);
253	        }
254	
255	        String reportPath = null;
256	        if (!allErrors.isEmpty()) {
257	            reportPath = writeErrorReport(job.getId(), allErrors);
258	        }
259	
260	        job.setTotalRows(total);
261	        job.setCreatedRows(created);
262	        job.setSkippedRows(skipped);
263	        job.setFailedRows(failed);
264	        job.setStatus(BulkImportJob.Status.COMPLETED);
265	        job.setCompletedAt(Instant.now());
266	        if (!allErrors.isEmpty()) {
267	            job.setErrorSummary(allErrors.size() + " row errors (see error report)");
268	            job.setErrorReportPath(reportPath);
269	        }
270	        BulkImportJob saved = jobRepository.save(job);
271	
272	        auditService.record(AuditAction.BULK_IMPORT_RUN, actorId(), actorUsername(),
273	                "BULK_IMPORT_JOB", String.valueOf(saved.getId()),
274	                "Students import: created=" + created + " skipped=" + skipped
275	                        + " failed=" + failed, sourceIp);
276	
277	        return new BulkImportResult(saved.getId(), total, created, skipped, failed, sample, reportPath);
278	    }
