296	    @Transactional(readOnly = true)
297	    public byte[] readErrorReport(Long jobId) {
298	        BulkImportJob job = jobRepository.findById(jobId)
299	                .orElseThrow(() -> new NotFoundException("Import job not found"));
300	        EffectiveScope scope = dataScopeService.forCurrentUser();
