306	        if (job.getErrorReportPath() == null) {
307	            throw new NotFoundException("Import job has no error report");
308	        }
309	        try {
310	            return Files.readAllBytes(Paths.get(job.getErrorReportPath()));
311	        } catch (IOException ioe) {
312	            throw new BusinessException("REPORT_READ_FAILED",
313	                    "Could not read error report: " + ioe.getMessage(),
314	                    HttpStatus.INTERNAL_SERVER_ERROR);
315	        }
316	    }
