318	    private static void recordError(List<BulkImportResult.RowError> sample,
319	                                    List<BulkImportResult.RowError> all,
320	                                    int lineNumber, String code, String message) {
321	        BulkImportResult.RowError err = new BulkImportResult.RowError(lineNumber, code, message);
322	        all.add(err);
323	        if (sample.size() < MAX_SAMPLE_ERRORS) {
324	            sample.add(err);
325	        }
326	    }
