328	    /**
329	     * Write the full error list to a CSV file under the tmpdir and return its
330	     * absolute path. Uses the job id in the filename so concurrent imports do
331	     * not clobber each other's reports.
332	     */
333	    private static String writeErrorReport(Long jobId, List<BulkImportResult.RowError> errors) {
334	        try {
335	            Path root = Paths.get(System.getProperty("java.io.tmpdir"), "dojostay-import-errors");
336	            Files.createDirectories(root);
337	            String fname = "student-import-" + jobId + "-"
338	                    + REPORT_STAMP.format(Instant.now()) + ".csv";
339	            Path target = root.resolve(fname);
340	            StringBuilder sb = new StringBuilder("lineNumber,code,message\n");
341	            for (BulkImportResult.RowError e : errors) {
342	                sb.append(e.lineNumber()).append(',')
343	                        .append(csvEscape(e.code())).append(',')
344	                        .append(csvEscape(e.message())).append('\n');
345	            }
346	            Files.writeString(target, sb.toString(), StandardCharsets.UTF_8);
347	            return target.toAbsolutePath().toString();
348	        } catch (IOException ioe) {
349	            // Do not fail the whole import because we couldn't spool the error report —
350	            // the caller still receives the sample errors in the API response.
351	            return null;
352	        }
353	    }
354	
355	    private static String csvEscape(String v) {
356	        if (v == null) return "";
357	        boolean needsQuote = v.indexOf(',') >= 0 || v.indexOf('"') >= 0 || v.indexOf('\n') >= 0;
358	        String escaped = v.replace("\"", "\"\"");
359	        return needsQuote ? "\"" + escaped + "\"" : escaped;
360	    }
