383	    private static Map<String, Integer> indexHeader(String header) {
384	        String[] cols = splitCsv(header);
385	        Map<String, Integer> out = new HashMap<>();
386	        for (int i = 0; i < cols.length; i++) {
387	            out.put(cols[i].trim(), i);
388	        }
389	        return out;
