392	    private static void requireColumn(Map<String, Integer> cols, String name) {
393	        if (!cols.containsKey(name)) {
394	            throw new BusinessException("MISSING_COLUMN",
395	                    "CSV is missing required column: " + name, HttpStatus.BAD_REQUEST);
396	        }
397	    }
