399	    private static String cell(String[] fields, Map<String, Integer> cols, String name) {
400	        Integer idx = cols.get(name);
401	        if (idx == null || idx >= fields.length) return null;
402	        String v = fields[idx];
403	        if (v == null) return null;
404	        v = v.trim();
405	        return v.isEmpty() ? null : v;
406	    }
