408	    /** Minimal CSV splitter supporting double-quoted fields with embedded commas. */
409	    private static String[] splitCsv(String line) {
410	        List<String> out = new ArrayList<>();
411	        StringBuilder cur = new StringBuilder();
412	        boolean inQuotes = false;
413	        for (int i = 0; i < line.length(); i++) {
414	            char c = line.charAt(i);
415	            if (inQuotes) {
416	                if (c == '"') {
417	                    if (i + 1 < line.length() && line.charAt(i + 1) == '"') {
418	                        cur.append('"');
419	                        i++;
420	                    } else {
421	                        inQuotes = false;
422	                    }
423	                } else {
424	                    cur.append(c);
425	                }
426	            } else if (c == ',') {
427	                out.add(cur.toString());
428	                cur.setLength(0);
429	            } else if (c == '"' && cur.length() == 0) {
430	                inQuotes = true;
431	            } else {
432	                cur.append(c);
433	            }
434	        }
435	        out.add(cur.toString());
436	        return out.toArray(new String[0]);
437	    }
