21	/**
22	 * Queues data export requests. Exports run out-of-process; this service only
23	 * tracks their lifecycle as rows in {@code export_jobs}. Callers submit via
24	 * {@link #request} and a worker eventually calls {@link #markCompleted} or
25	 * {@link #markFailed}. Scope filtering: users see only their own requests
26	 * unless they are in a fullAccess scope.
27	 */
28	@Service
29	public class ExportJobService {
30	
31	    private final ExportJobRepository repository;
32	    private final DataScopeService dataScopeService;
33	    private final AuditService auditService;
34	
35	    public ExportJobService(ExportJobRepository repository,
36	                            DataScopeService dataScopeService,
37	                            AuditService auditService) {
38	        this.repository = repository;
39	        this.dataScopeService = dataScopeService;
40	        this.auditService = auditService;
41	    }
42	
43	    @Transactional(readOnly = true)
44	    public List<ExportJobResponse> listMine() {
45	        Long me = requireActor();
46	        EffectiveScope scope = dataScopeService.forCurrentUser();
47	        if (scope.fullAccess()) {
48	            return repository.findAll().stream()
49	                    .map(ExportJobService::toResponse)
50	                    .toList();
51	        }
52	        return repository.findByRequestedByUserIdOrderByIdDesc(me).stream()
53	                .map(ExportJobService::toResponse)
54	                .toList();
55	    }
