57	    @Transactional
58	    public ExportJobResponse request(CreateExportJobRequest req, String sourceIp) {
59	        EffectiveScope scope = dataScopeService.forCurrentUser();
60	        if (req.organizationId() != null
61	                && !scope.fullAccess()
62	                && !scope.hasOrganization(req.organizationId())) {
63	            throw new BusinessException("OUT_OF_SCOPE",
64	                    "Target organization is not in your data scope",
65	                    HttpStatus.FORBIDDEN);
66	        }
67	        ExportJob job = new ExportJob();
68	        job.setOrganizationId(req.organizationId());
69	        job.setRequestedByUserId(requireActor());
70	        job.setKind(req.kind());
71	        job.setFormat(req.format());
72	        job.setStatus(ExportJob.Status.QUEUED);
73	        job.setWatermarkText(buildWatermark(actorUsername(), Instant.now()));
74	        ExportJob saved = repository.save(job);
75	
76	        auditService.record(AuditAction.EXPORT_REQUESTED, actorId(), actorUsername(),
77	                "EXPORT_JOB", String.valueOf(saved.getId()),
78	                "kind=" + req.kind() + " format=" + req.format()
79	                        + " watermark=" + saved.getWatermarkText(),
80	                sourceIp);
81	        return toResponse(saved);
82	    }
