84	    /**
85	     * Build the proof-of-origin watermark that will be stamped onto the
86	     * artifact. Format: {@code "<username> <ISO8601 instant>"}. Kept short
87	     * enough to fit the 255-char column and safe to render inline in CSV/JSON.
88	     */
89	    static String buildWatermark(String username, Instant when) {
90	        String safeUser = username == null ? "system" : username;
91	        return safeUser + " " + DateTimeFormatter.ISO_INSTANT.format(when);
92	    }
