1	import { defineStore } from 'pinia';
2	import { authApi, type LoginPayload } from '@/api/auth';
3	import type { CurrentUser, UserRoleType } from '@/types/api';
4	
5	interface AuthState {
6	  user: CurrentUser | null;
7	  loading: boolean;
8	  initialized: boolean;
9	}
10	
11	export const useAuthStore = defineStore('auth', {
12	  state: (): AuthState => ({
13	    user: null,
14	    loading: false,
15	    initialized: false,
16	  }),
17	  getters: {
18	    isAuthenticated: (state): boolean => state.user !== null,
19	    primaryRole: (state): UserRoleType | null => state.user?.primaryRole ?? null,
20	    hasRole: (state) => (code: string): boolean => state.user?.roles?.includes(code) ?? false,
21	    hasPermission: (state) => (code: string): boolean =>
22	      state.user?.permissions?.includes(code) ?? false,
23	  },
24	  actions: {
25	    async login(payload: LoginPayload): Promise<void> {
26	      this.loading = true;
27	      try {
28	        this.user = await authApi.login(payload);
29	      } finally {
30	        this.loading = false;
31	      }
32	    },
33	    async logout(): Promise<void> {
34	      try {
35	        await authApi.logout();
36	      } finally {
37	        this.user = null;
38	      }
39	    },
40	    async refresh(): Promise<void> {
41	      try {
42	        this.user = await authApi.me();
43	      } catch {
44	        this.user = null;
45	      } finally {
46	        this.initialized = true;
47	      }
48	    },
49	  },
50	});
