1	package com.dojostay.training;
2	
3	import com.dojostay.audit.AuditAction;
4	import com.dojostay.audit.AuditService;
5	import com.dojostay.auth.CurrentUser;
6	import com.dojostay.auth.CurrentUserResolver;
7	import com.dojostay.common.exception.BusinessException;
8	import com.dojostay.common.exception.NotFoundException;
9	import com.dojostay.scopes.DataScopeService;
10	import com.dojostay.scopes.EffectiveScope;
11	import com.dojostay.training.dto.CreateTrainingClassRequest;
12	import com.dojostay.training.dto.CreateTrainingSessionRequest;
13	import com.dojostay.training.dto.TrainingClassResponse;
14	import com.dojostay.training.dto.TrainingSessionResponse;
15	import org.springframework.http.HttpStatus;
16	import org.springframework.stereotype.Service;
17	import org.springframework.transaction.annotation.Transactional;
18	
19	import java.time.Instant;
20	import java.time.temporal.ChronoUnit;
21	import java.util.List;
22	
23	/**
24	 * Training-side of Phase 5: manages reusable class templates and the scheduled
25	 * session instances that students book. Read paths are scope-filtered. Writes
26	 * emit {@link AuditAction#TRAINING_SESSION_CREATED} and
27	 * {@link AuditAction#TRAINING_SESSION_CANCELLED} events.
28	 */
29	@Service
30	public class TrainingService {
31	
32	    private final TrainingClassRepository classRepository;
33	    private final TrainingSessionRepository sessionRepository;
34	    private final BookingRepository bookingRepository;
35	    private final DataScopeService dataScopeService;
36	    private final AuditService auditService;
37	
38	    public TrainingService(TrainingClassRepository classRepository,
39	                           TrainingSessionRepository sessionRepository,
40	                           BookingRepository bookingRepository,
41	                           DataScopeService dataScopeService,
42	                           AuditService auditService) {
43	        this.classRepository = classRepository;
44	        this.sessionRepository = sessionRepository;
45	        this.bookingRepository = bookingRepository;
46	        this.dataScopeService = dataScopeService;
47	        this.auditService = auditService;
48	    }
49	
50	    @Transactional(readOnly = true)
51	    public List<TrainingClassResponse> listClasses() {
52	        EffectiveScope scope = dataScopeService.forCurrentUser();
53	        return classRepository.findAll().stream()
54	                .filter(c -> scope.fullAccess() || scope.hasOrganization(c.getOrganizationId()))
55	                .map(TrainingService::toClassResponse)
56	                .toList();
57	    }
58	
59	    @Transactional
60	    public TrainingClassResponse createClass(CreateTrainingClassRequest req, String sourceIp) {
61	        assertOrgAccessible(req.organizationId());
62	        classRepository.findByOrganizationIdAndCode(req.organizationId(), req.code()).ifPresent(c -> {
63	            throw new BusinessException("DUPLICATE_CLASS_CODE",
64	                    "A training class with that code already exists in this organization",
65	                    HttpStatus.CONFLICT);
66	        });
67	        TrainingClass tc = new TrainingClass();
68	        tc.setOrganizationId(req.organizationId());
69	        tc.setCode(req.code());
70	        tc.setName(req.name());
71	        tc.setDiscipline(req.discipline());
72	        tc.setLevel(req.level());
73	        tc.setDefaultCapacity(req.defaultCapacity());
74	        tc.setDescription(req.description());
75	        TrainingClass saved = classRepository.save(tc);
76	
77	        auditService.record(AuditAction.TRAINING_SESSION_CREATED, actorId(), actorUsername(),
78	                "TRAINING_CLASS", String.valueOf(saved.getId()),
79	                "Training class created: " + saved.getCode(), sourceIp);
80	        return toClassResponse(saved);
81	    }
82	
83	    @Transactional(readOnly = true)
84	    public List<TrainingSessionResponse> listSessionsForClass(Long trainingClassId) {
85	        TrainingClass tc = loadAccessibleClass(trainingClassId);
86	        return sessionRepository.findByTrainingClassId(tc.getId()).stream()
87	                .map(this::toSessionResponse)
88	                .toList();
89	    }
90	
91	    @Transactional
92	    public TrainingSessionResponse createSession(CreateTrainingSessionRequest req, String sourceIp) {
93	        if (!req.endsAt().isAfter(req.startsAt())) {
94	            throw new BusinessException("INVALID_RANGE",
95	                    "endsAt must be strictly after startsAt", HttpStatus.BAD_REQUEST);
96	        }
97	        // Phase B6: enforce 30-minute slot alignment. Both endpoints must land on
98	        // a :00 / :30 boundary and the duration must be a positive multiple of
99	        // 30 minutes. We measure from epoch so the grid is DST-agnostic.
100	        assertSlotAligned(req.startsAt(), "startsAt");
101	        assertSlotAligned(req.endsAt(), "endsAt");
102	        long durationMinutes = ChronoUnit.MINUTES.between(req.startsAt(), req.endsAt());
103	        if (durationMinutes <= 0 || durationMinutes % 30 != 0) {
104	            throw new BusinessException("INVALID_SLOT_DURATION",
105	                    "Session duration must be a positive multiple of 30 minutes",
106	                    HttpStatus.BAD_REQUEST);
107	        }
108	        if (req.sessionType() == TrainingSession.SessionType.ONLINE
109	                && (req.onlineUrl() == null || req.onlineUrl().isBlank())) {
110	            throw new BusinessException("ONLINE_URL_REQUIRED",
111	                    "Online sessions must include an onlineUrl",
112	                    HttpStatus.BAD_REQUEST);
113	        }
114	        TrainingClass tc = loadAccessibleClass(req.trainingClassId());
115	        TrainingSession s = new TrainingSession();
116	        s.setTrainingClassId(tc.getId());
117	        s.setOrganizationId(tc.getOrganizationId());
118	        s.setStartsAt(req.startsAt());
119	        s.setEndsAt(req.endsAt());
120	        s.setLocation(req.location());
121	        s.setInstructorUserId(req.instructorUserId());
122	        s.setCapacity(req.capacity() != null ? req.capacity() : tc.getDefaultCapacity());
123	        s.setNotes(req.notes());
124	        s.setStatus(TrainingSession.Status.SCHEDULED);
125	        s.setSessionType(req.sessionType());
126	        s.setOnlineUrl(req.onlineUrl());
127	        s.setLevel(req.level());
128	        s.setWeightClassLbs(req.weightClassLbs());
129	        s.setStyle(req.style());
130	        TrainingSession saved = sessionRepository.save(s);
131	
132	        auditService.record(AuditAction.TRAINING_SESSION_CREATED, actorId(), actorUsername(),
133	                "TRAINING_SESSION", String.valueOf(saved.getId()),
134	                "Session scheduled at " + saved.getStartsAt(), sourceIp);
135	        return toSessionResponse(saved);
136	    }
137	
138	    /**
139	     * Reject anything not on a :00 or :30 clock boundary. We work in whole
140	     * epoch-minutes so the grid is insensitive to time-zone offsets.
141	     */
142	    private static void assertSlotAligned(Instant t, String fieldName) {
143	        long epochMinutes = t.getEpochSecond() / 60;
144	        if (t.getEpochSecond() % 60 != 0 || epochMinutes % 30 != 0) {
145	            throw new BusinessException("INVALID_SLOT_ALIGNMENT",
146	                    fieldName + " must fall on a 30-minute boundary (HH:00 or HH:30)",
147	                    HttpStatus.BAD_REQUEST);
148	        }
149	    }
150	
151	    /**
152	     * Phase B6: filter listing for sparring matching. All predicates are
153	     * optional; any combination narrows the result set. Scope is applied first
154	     * so filters only operate on rows the caller can already see.
155	     */
156	    @Transactional(readOnly = true)
157	    public List<TrainingSessionResponse> filterSessions(
158	            TrainingSession.SessionType sessionType,
159	            String level,
160	            Integer weightClassLbs,
161	            String style,
162	            Instant from,
163	            Instant to) {
164	        EffectiveScope scope = dataScopeService.forCurrentUser();
165	        return sessionRepository.findAll().stream()
166	                .filter(s -> scope.fullAccess() || scope.hasOrganization(s.getOrganizationId()))
167	                .filter(s -> sessionType == null || sessionType == s.getSessionType())
168	                .filter(s -> level == null || level.equalsIgnoreCase(s.getLevel()))
169	                .filter(s -> weightClassLbs == null
170	                        || (s.getWeightClassLbs() != null
171	                                && s.getWeightClassLbs().equals(weightClassLbs)))
172	                .filter(s -> style == null || style.equalsIgnoreCase(s.getStyle()))
173	                .filter(s -> from == null || !s.getStartsAt().isBefore(from))
174	                .filter(s -> to == null || !s.getEndsAt().isAfter(to))
175	                .map(this::toSessionResponse)
176	                .toList();
177	    }
178	
179	    @Transactional
180	    public TrainingSessionResponse cancelSession(Long sessionId, String sourceIp) {
181	        TrainingSession s = sessionRepository.findById(sessionId)
182	                .orElseThrow(() -> new NotFoundException("Training session not found"));
183	        assertOrgAccessibleRead(s.getOrganizationId(), "Training session not found");
184	        if (s.getStatus() == TrainingSession.Status.CANCELLED) {
185	            return toSessionResponse(s);
186	        }
187	        s.setStatus(TrainingSession.Status.CANCELLED);
188	        s.setCancelledAt(Instant.now());
189	        TrainingSession saved = sessionRepository.save(s);
190	        auditService.record(AuditAction.TRAINING_SESSION_CANCELLED, actorId(), actorUsername(),
191	                "TRAINING_SESSION", String.valueOf(saved.getId()),
192	                "Training session cancelled", sourceIp);
193	        return toSessionResponse(saved);
194	    }
195	
196	    TrainingSession loadAccessibleSession(Long sessionId) {
197	        TrainingSession s = sessionRepository.findById(sessionId)
198	                .orElseThrow(() -> new NotFoundException("Training session not found"));
199	        EffectiveScope scope = dataScopeService.forCurrentUser();
200	        if (!scope.fullAccess() && !scope.hasOrganization(s.getOrganizationId())) {
201	            throw new NotFoundException("Training session not found");
202	        }
203	        return s;
204	    }
205	
206	    private TrainingClass loadAccessibleClass(Long classId) {
207	        TrainingClass tc = classRepository.findById(classId)
208	                .orElseThrow(() -> new NotFoundException("Training class not found"));
209	        EffectiveScope scope = dataScopeService.forCurrentUser();
210	        if (!scope.fullAccess() && !scope.hasOrganization(tc.getOrganizationId())) {
211	            throw new NotFoundException("Training class not found");
212	        }
213	        return tc;
214	    }
215	
216	    private void assertOrgAccessible(Long organizationId) {
217	        EffectiveScope scope = dataScopeService.forCurrentUser();
218	        if (scope.fullAccess()) return;
219	        if (organizationId == null || !scope.hasOrganization(organizationId)) {
220	            throw new BusinessException("OUT_OF_SCOPE",
221	                    "Target organization is not in your data scope",
222	                    HttpStatus.FORBIDDEN);
223	        }
224	    }
225	
226	    private void assertOrgAccessibleRead(Long organizationId, String notFoundMessage) {
227	        EffectiveScope scope = dataScopeService.forCurrentUser();
228	        if (scope.fullAccess()) return;
229	        if (organizationId == null || !scope.hasOrganization(organizationId)) {
230	            throw new NotFoundException(notFoundMessage);
231	        }
232	    }
233	
234	    private static TrainingClassResponse toClassResponse(TrainingClass c) {
235	        return new TrainingClassResponse(
236	                c.getId(), c.getOrganizationId(), c.getCode(), c.getName(),
237	                c.getDiscipline(), c.getLevel(), c.getDefaultCapacity(),
238	                c.getDescription(), c.isActive(), c.getCreatedAt()
239	        );
240	    }
241	
242	    private TrainingSessionResponse toSessionResponse(TrainingSession s) {
243	        long booked = bookingRepository.countActiveBookingsForSession(s.getId());
244	        return new TrainingSessionResponse(
245	                s.getId(), s.getTrainingClassId(), s.getOrganizationId(),
246	                s.getStartsAt(), s.getEndsAt(), s.getLocation(),
247	                s.getInstructorUserId(), s.getCapacity(), booked,
248	                s.getStatus(), s.getNotes(),
249	                s.getSessionType(), s.getOnlineUrl(), s.getLevel(),
250	                s.getWeightClassLbs(), s.getStyle(),
251	                s.getCreatedAt(), s.getCancelledAt()
252	        );
253	    }
254	
255	    private static Long actorId() {
256	        return CurrentUserResolver.current().map(CurrentUser::id).orElse(null);
257	    }
258	
259	    private static String actorUsername() {
260	        return CurrentUserResolver.current().map(CurrentUser::username).orElse("system");
261	    }
262	}
