1	import axios, { type AxiosError, type AxiosInstance } from 'axios';
2	import type { ApiError, ApiResponse } from '@/types/api';
3	
4	/**
5	 * Centralized Axios instance.
6	 *
7	 * Responsibilities:
8	 *  - send credentials (cookies) so server-side sessions work
9	 *  - reflect the XSRF cookie back as X-XSRF-TOKEN header (Spring CSRF cookie repo)
10	 *  - unwrap the {success, data, error} envelope so callers get plain T
11	 *  - normalize errors into a typed ApiError that toasts/forms can render
12	 */
13	export const http: AxiosInstance = axios.create({
14	  baseURL: '/',
15	  withCredentials: true,
16	  xsrfCookieName: 'XSRF-TOKEN',
17	  xsrfHeaderName: 'X-XSRF-TOKEN',
18	  headers: {
19	    'Content-Type': 'application/json',
20	    Accept: 'application/json',
21	  },
22	});
23	
24	export class ApiException extends Error {
25	  readonly status: number;
26	  readonly apiError: ApiError;
27	  readonly traceId: string | null;
28	
29	  constructor(status: number, apiError: ApiError, traceId: string | null) {
30	    super(apiError.message);
31	    this.status = status;
32	    this.apiError = apiError;
33	    this.traceId = traceId;
