37	function unwrap<T>(envelope: ApiResponse<T>): T {
38	  if (envelope.success) {
39	    // data may be null for 200 OK with no body (envelope.empty()).
40	    return envelope.data as T;
41	  }
42	  throw new ApiException(
43	    200,
44	    envelope.error ?? { code: 'UNKNOWN', message: 'Unknown error' },
45	    envelope.traceId,
46	  );
