58	  (error: AxiosError<ApiResponse<unknown>>) => {
59	    const status = error.response?.status ?? 0;
60	    const envelope = error.response?.data;
61	    const apiErr: ApiError = envelope?.error ?? {
62	      code: status === 0 ? 'NETWORK_ERROR' : 'HTTP_' + status,
63	      message:
