2	import { onMounted, ref } from 'vue';
3	import { notificationsApi, type Notification } from '@/api/notifications';
4	import { ApiException } from '@/api/client';
5	import { useToast } from '@/composables/useToast';
6	
7	const toast = useToast();
8	const loading = ref(false);
9	const notifications = ref<Notification[]>([]);
10	
11	async function load() {
12	  loading.value = true;
13	  try {
14	    notifications.value = await notificationsApi.list();
15	  } catch (err) {
16	    toast.error(err instanceof ApiException ? err.apiError.message : 'Failed to load notifications');
17	  } finally {
18	    loading.value = false;
19	  }
20	}
21	
22	async function markRead(n: Notification) {
23	  if (n.readAt) return;
24	  try {
25	    const updated = await notificationsApi.markRead(n.id);
26	    notifications.value = notifications.value.map(x => x.id === updated.id ? updated : x);
27	  } catch {
28	    toast.error('Failed to mark as read');
29	  }
30	}
31	
32	function formatDate(iso: string): string {
33	  return new Date(iso).toLocaleString();
34	}
35	
36	onMounted(load);
