        // 16-byte key (base64 of 16 bytes)
        String shortKey = "MTIzNDU2Nzg5MDEyMzQ1Ng==";
        assertThrows(IllegalStateException.class,
                () -> new SensitiveStringConverter(shortKey, "prod"));
    }

